import{_ as t,o as a,c as o,a0 as r}from"./chunks/framework.DgPozsi0.js";const l="/vitepress-study/assets/nextDev_01_01.BZbBTBky.avif",g=JSON.parse('{"title":"[Next.js官網] Next.js 16.2 教程","description":"","frontmatter":{"title":"[Next.js官網] Next.js 16.2 教程","outline":2},"headers":[],"relativePath":"pages/f2e/docReact/nextDev/nextDev_01.md","filePath":"pages/f2e/docReact/nextDev/nextDev_01.md"}'),i={name:"pages/f2e/docReact/nextDev/nextDev_01.md"};function n(s,e,c,d,p,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="app-router" tabindex="-1">App Router <a class="header-anchor" href="#app-router" aria-label="Permalink to &quot;App Router&quot;">​</a></h1><p>歡迎來到 <code>Next.js</code> <code>Foundations</code> 課程！在這個免費的互動課程中，你將透過建構一個全端網頁應用程式來學習 <code>Next.js</code> 的主要功能。</p><h2 id="我們將建構什麼" tabindex="-1">我們將建構什麼 <a class="header-anchor" href="#我們將建構什麼" aria-label="Permalink to &quot;我們將建構什麼&quot;">​</a></h2><p><img src="'+l+'" alt="儀表板專案的桌面版與行動版畫面截圖"></p><ul><li><p>在這門課程中，我們將建構一個財務儀表板，其中包含:</p><ul><li>一個公開的首頁</li><li>一個登入頁面</li><li>需要透過驗證才能存取的儀表板頁面</li><li>使用者可以新增、編輯、刪除發票的功能</li></ul></li><li><p>這個儀表板還會搭配一個資料庫，你將在 <a href="/vitepress-study/pages/f2e/docReact/nextDev/01/nextDev_01_06.html">稍後的章節</a> 中設定它。</p></li><li><p>在課程結束時，你將具備開始建構全端 <code>Next.js</code> 應用程式所需的核心技能。</p></li></ul><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><ul><li>以下是這門課程中你將學到的功能概覽： <ul><li><p><strong>樣式設計(Styling)</strong>：在 <code>Next.js</code> 中為應用程式設計樣式的各種方式。</p></li><li><p><strong>最佳化(Optimizations)</strong>：如何最佳化圖片、連結與字型。</p></li><li><p><strong>路由(Routing)</strong>：如何使用檔案系統路由建立巢狀版面配置與頁面。</p></li><li><p><strong>資料擷取(Data Fetching)</strong>：如何在 <code>Vercel</code> 上設定 <code>Postgres</code> 資料庫，以及擷取與串流資料的最佳實務。</p></li><li><p><strong>搜尋與分頁(Search and Pagination)</strong>：如何使用 <code>URL</code> 搜尋參數實作搜尋與分頁功能。</p></li><li><p><strong>資料異動(Mutating Data)</strong>：如何使用 <code>React Server Actions</code> 異動資料，並重新驗證 <code>Next.js</code> 快取。</p></li><li><p><strong>錯誤處理(Error Handling)</strong>：如何處理一般錯誤及 <code>404</code> 找不到頁面的錯誤。</p></li><li><p><strong>表單驗證與無障礙設計(Form Validation and Accessibility)</strong>：如何進行伺服器端的表單驗證，以及提升無障礙性的技巧。</p></li><li><p><strong>驗證(Authentication)</strong>：如何使用 <a href="https://next-auth.js.org/" target="_blank" rel="noreferrer"><code>NextAuth.js</code></a> 與 <code>Proxy</code> 為應用程式加入身分驗證。</p></li><li><p><strong>中繼資料(Metadata)</strong>：如何新增中繼資料，並為應用程式的社群分享做好準備。</p></li></ul></li></ul><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li>這門課程假設你已具備 <code>React</code> 與 <code>JavaScript</code> 的基本理解。如果你剛接觸 <code>React</code>，建議先修習 <a href="/vitepress-study/pages/f2e/docReact/nextDev/nextDev_03.html">React 基礎</a> 課程，學習 <code>React</code> 的基礎概念，例如元件、props、state、hooks，以及較新的功能如 Server Components 與 Suspense。</li></ul><h2 id="系統需求" tabindex="-1">系統需求 <a class="header-anchor" href="#系統需求" aria-label="Permalink to &quot;系統需求&quot;">​</a></h2><ul><li><p>在開始這門課程之前，請確認你的系統符合以下需求:</p><ul><li>已安裝<code> Node.js 20.9</code> 或更新版本。<a href="https://nodejs.org/en" target="_blank" rel="noreferrer">點此下載</a>。</li><li>作業系統：<code>macOS</code>、<code>Windows</code>(含 WSL)或 <code>Linux</code>。</li></ul></li><li><p>此外，你還需要一個 <a href="https://github.com/join/" target="_blank" rel="noreferrer">GitHub 帳號</a> 以及一個 <a href="https://vercel.com/signup" target="_blank" rel="noreferrer">Vercel 帳號</a>。</p></li></ul><h2 id="加入討論" tabindex="-1">加入討論 <a class="header-anchor" href="#加入討論" aria-label="Permalink to &quot;加入討論&quot;">​</a></h2><ul><li>如果你對這門課程有任何疑問或想提供意見回饋，可以在 <a href="https://reddit.com/r/vercel" target="_blank" rel="noreferrer">Reddit</a> 或 <a href="https://github.com/vercel/next-learn" target="_blank" rel="noreferrer">GitHub</a> 上向社群提問。</li></ul><h2 id="準備好開始了嗎" tabindex="-1">準備好開始了嗎? <a class="header-anchor" href="#準備好開始了嗎" aria-label="Permalink to &quot;準備好開始了嗎?&quot;">​</a></h2><ul><li>既然你已經認識了這門課程，讓我們開始吧。</li></ul>',15)])])}const _=t(i,[["render",n]]);export{g as __pageData,_ as default};
